import { useEffect, useRef, useState } from 'react';
import { Select, Table, Typography } from 'antd';
import BigNumber from 'bignumber.js';
import config from '../config';
import './index.css';

BigNumber.config({ EXPONENTIAL_AT: 1e9 });

function App() {
  const [coinData, setCoinData] = useState([]);
  const [coins, setCoins] = useState([]);
  const [symbol, setSymbol] = useState('BCH');
  const [tableCols] = useState([
    {
      title: '#',
      dataIndex: 'id',
      fixed: 'left',
      width: 200,
      render: (text, record) => <Typography.Text type={record.symbol === record.highlight ? 'success' : ''}>{text}</Typography.Text>
    },
    {
      title: 'Symbol',
      dataIndex: 'symbol',
      render: (text, record) => (
        <Typography.Link href={`${config.coinmarketcap.detail}${record.slug}`} target="_blank" rel="noreferrer">
          {text}
        </Typography.Link>
      )
    },
    {
      title: 'Market Cap',
      dataIndex: 'marketCap',
      render: (text, record) => <Typography.Text type={record.symbol === record.highlight ? 'success' : ''}>{text}</Typography.Text>
    },
    {
      title: 'Price',
      dataIndex: 'price',
      render: (text, record) => <Typography.Text type={record.symbol === record.highlight ? 'success' : ''}>{text}</Typography.Text>
    },
    {
      title: `${symbol} Target`,
      dataIndex: 'target',
      render: (text, record) => <Typography.Text type={record.symbol === record.highlight ? 'success' : ''}>{text}</Typography.Text>
    }
  ]);
  const [tableData, setTableData] = useState([]);

  const ref = useRef(null);
  const tableRef = useRef(null);
  ref.current = async () => {
    const data = await (await fetch(config.coinmarketcap.url)).json();
    const symbols = data.map(_ => _.symbol);
    setCoinData(data);
    setCoins(symbols);
  };
  tableRef.current = () => {
    const data = [];

    const capData = coinData.map(_ => {
      const {
        slug,
        symbol,
        total_supply,
        quote: {
          USD: { price, market_cap }
        }
      } = _;
      return {
        slug,
        symbol,
        totalSupply: total_supply,
        price,
        marketCap: market_cap
      };
    });
    const targetCap = capData.filter(_ => _.symbol === symbol)[0];
    capData.forEach((_, i) => {
      const { slug, symbol, price, marketCap } = _;
      const target = BigNumber(marketCap).div(targetCap.totalSupply);
      data.push({
        id: i,
        slug,
        symbol,
        highlight: targetCap.symbol,
        marketCap: `${toFormat(marketCap)}`,
        price: `${toFormat(price)}`,
        target: `${toFormat(target)} (${toFormat(BigNumber(target).minus(targetCap.price).div(targetCap.price).times(100))}%)`
      });
    });

    tableCols[tableCols.length - 1].title = `${symbol} Target`;
    setTableData(data);
  };

  const toFormat = _ => BigNumber(BigNumber(_).toFixed(2, BigNumber.ROUND_DOWN)).toFormat();

  useEffect(() => {
    const timer = setTimeout(() => {
      tableRef.current();
    }, 200);

    return () => {
      clearTimeout(timer);
    };
  }, [coins, symbol, tableCols]);

  useEffect(() => {
    ref.current();
  }, []);

  return (
    <div className="cm-app">
      <div className="cm-symbol">
        <Select
          showSearch
          defaultValue={symbol}
          style={{ width: 120 }}
          onChange={_ => setSymbol(_)}
          filterOption={(input, option) => (option?.label ?? '').toLowerCase().includes(input.toLowerCase())}
          options={coins.map(_ => {
            return {
              value: _,
              label: _
            };
          })}
        />
      </div>

      <Table columns={tableCols} dataSource={tableData} scroll={{ x: 'max-content' }} pagination={{ pageSize: 100 }} />
    </div>
  );
}

export default App;
